#include<bits/stdc++.h>
using namespace std;
vector<pair<int,double>> mp[500010];
double f[500010];
const double eps=1e-7;
void dfs(int x,int fa=-1)
{
	for(auto i:mp[x])
	{
		int v=i.first;
		double val=i.second;
		if(v!=fa)
		{
			dfs(v,x);
			double a=f[x],b=f[v]*val;
			f[x]=a+b-a*b;
		}
	}
}
void dfs2(int x,int fa=-1)
{
	for(auto i:mp[x])
	{
		int v=i.first;
		double val=i.second;
		if(v!=fa)
		{
			if(abs(f[v]*val-1)<eps)
			{
				dfs2(v,x);
				continue;
			}
			double a=f[v];
			double b=((f[x]-f[v]*val)/(1-f[v]*val))*val;
			f[v]=a+b-a*b;
			dfs2(v,x);
		}
	}
}
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<n;i++)
	{
		int u,v;
		double w;
		scanf("%d%d%lf",&u,&v,&w);
		w/=100.0;
		mp[u].push_back({v,w});
		mp[v].push_back({u,w});
	}
	for(int i=1;i<=n;i++)
	{
		scanf("%lf",&f[i]);
		f[i]/=100.0;
	}
	dfs(1);
	dfs2(1);
	double ans=0;
	for(int i=1;i<=n;i++)
	{
		ans+=f[i];
	}
	printf("%.6lf",ans);
	return 0;
}
